var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"흐으음. 터커를 따르는 멍청이들이 제법 되네.","JPN":"ふーん。ターカーに従うアホが結構多いな。","ENG":"Hmm, there are a lot of Tucker's goons.","TWN":"哼。追隨塔克的傻蛋還真不少呢。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"검은 범람이 좋은 커리어가 됐나 봐?","JPN":"黒い氾濫って、それなりのキャリアになったのか？","ENG":"Guess the Black Flood helped your career, eh?","TWN":"黑色洪災促成了不少職業呢？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SPEAKER_DEBT_NULL_NULL","text":{"KOREA":"으읍! 으으으읍!","JPN":"ううっ！　ううううっ！","ENG":"Mmf! Mmph!!","TWN":"唔！唔唔——！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L5_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"뭐, 그래봤자 일반인이나 다름없는 애송이들이지만.","JPN":"まあ、だからって一般人と変わらない小僧どもだけどさ。","ENG":"Still, you're all just chumps who are no different from civilians.","TWN":"不過，也就是些和普通人沒什麼兩樣的小毛頭而已。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"이런 녀석들로 해적이라니. 터커 녀석도 어지간히 보는 눈이 없구만.","JPN":"こんなやつらが海賊だなんて。ターカーのやつ見る目がないんだな。","ENG":"To let these punks become pirates. Tucker's got a bad eye for people.","TWN":"這些人也能當海盜，塔克那傢伙真是沒眼光。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SPEAKER_DEBT_NULL_NULL","text":{"KOREA":"읍! 읍읍읍!!","JPN":"うっ！　うううっ！！","ENG":"Mmff! MMMMPH!!","TWN":"唔！唔唔唔！！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L9_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"선장. 이 사람 아까부터 뭔가 말하고 있어.","JPN":"船長。この人、さっきから何か言ってる。","ENG":"Captain, I think she's trying to say something.","TWN":"船長，這個人從剛才開始就想說些什麼。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"흐흥~ 보나마나 살려달라는 거겠죠. 이래서 사람이 줄을 잘 서야 하는 거라고요.","JPN":"ふふん～。きっと助けてくださいとかですわね。だから誰につくかは慎重に決めるべきなんです。","ENG":"Pfft. I bet she's pleading for her life. This is why choices in life matter.","TWN":"哼哼～想也知道是要求饒吧。這就是為什麼人要站對邊。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L11_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"우리 선장님이 성격은 더럽고 입도 험하고 윙스타 관심종자여도 나름 A급 카운터니까!","JPN":"私たちの船長は性格悪いし口も汚いしウィングスター中毒だけど、A級カウンターですから！","ENG":"Our captain may have a bad personality and a pirate's mouth, and she may be an attention-seeker on Wing-stagram, but she's still a Grade A Counter!","TWN":"我們船長雖然暴躁、嘴巴毒，還總是划手機，但好歹也是A級制裁者！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"소냐. 저 녀석 생선 미끼로 던져버려.","JPN":"ソーニャ。あいつ、魚のエサにしてやれ。","ENG":"Sonya, toss her overboard as fish bait.","TWN":"索妮雅，把那傢伙扔去餵魚吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"미안. 난 시끄러운 건 딱 질색이거든.","JPN":"ごめん。あたし、うるさいのは大嫌いだから。","ENG":"Sorry. You see, I hate noisy things.","TWN":"抱歉，我也最討厭吵鬧了。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L18_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"얼추 쉬었으니, 난 숨어 있는 녀석들이나 찾으러 갈게.","JPN":"一休みしたし、あたしは隠れてるやつらを探してみる。","ENG":"Now that we've rested, I'll go find the grunts who are in hiding.","TWN":"差不多休息夠了，我去找那些躲起來的傢伙。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"그거 잘 됐네. 마침 나도 심심해지던 참이었걸랑.","JPN":"そりゃいい。ちょうどあたしも暇だったんだ。","ENG":"Good timing. I was getting a little restless myself.","TWN":"那正好，我也有點無聊了。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L20_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"꼬리 말고 도망친 허접들은 어떤 표정인지 구경이나 해보자고.","JPN":"尻尾をまいて逃げたヘタクソどもはどんな顔をしてるのか、見てみようじゃないか。","ENG":"Let's see what faces these tail-tucking scurvy dogs will make.","TWN":"那些逃跑的弱雞們現在是什麼表情呢，真想看看。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L25_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"탈리. 인질 어디 안 가는지 잘 보고 있어라~.","JPN":"タリー。人質が逃げないようにちゃんと見てろよ～。","ENG":"Tallie, you stay here and keep an eye on our hostage.","TWN":"塔莉。好好看著人質，別讓人跑了。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"넵. 맡겨만 주세요!","JPN":"はいっ。任せてください！","ENG":"Okay! Leave it to me!","TWN":"好，包在我身上！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"우에엥-! 생각해보니 부당해요. 원래 이런 허드렛일은 막내가 하는 거라고요!","JPN":"びえーん！　考えてみると不合理ですわ。こんな雑務は下っ端がやるものでしょう！","ENG":"Waah! Wait, this is so unfair! These kinds of jobs are supposed to be done by the rookie!","TWN":"哇嗚！不對不對！這種雜事應該是讓新人來做的吧？真不公平！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L29_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"하다못해 가위바위보로 정해요──!!","JPN":"せめてじゃんけんで決めましょうよー！！","ENG":"Can we at least decide on rock, paper, scissors?!","TWN":"至少用猜拳來決定嘛——！！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING_02"},{"id":"L33_1","type":"dialog","speaker":"SPEAKER_DEBT_NULL_NULL","text":{"KOREA":"뭐야, 저 사람들. 진짜 이렇게 가버린다고?","JPN":"なんなの、あの人たち。本当にこのまま行っちゃうの？","ENG":"What? Seriously? They're just going to leave me like this?","TWN":"什麼啊，那些人。真的就這樣走啦？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L34_1","type":"dialog","speaker":"SPEAKER_DEBT_NULL_NULL","text":{"KOREA":"멍청하긴. 기업제가 겉만 번지르르한 해적선인 줄 아나…?","JPN":"バカだね。企業製は外見だけ立派だと思ってる……？","ENG":"How stupid are they? Do they think that this corporate-made ship is just for show...?","TWN":"真是愚蠢，你們以為這艘只是單純的海盜船嗎……?"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SPEAKER_DEBT_NULL_NULL","text":{"KOREA":"손발이 묶여 있어도 구조 신호는 얼마든지 보낼 수 있다고.","JPN":"手足が縛られていても、救助信号はいくらでも送れるし。","ENG":"I can still call a rescue signal even if I'm tied up.","TWN":"即使手腳被綁住，也可以隨時發送求救信號。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SPEAKER_DEBT_NULL_NULL","text":{"KOREA":"좋아. 긴급 서버에는 무사히 접속했어. 이제 버튼을 누르면…….","JPN":"よし。緊急サーバーには無事アクセスできた。あとはボタンさえ押せば……","ENG":"Okay. I've successfully connected to the emergency server. Now, all I have to do is press the butto–","TWN":"好。已經順利連接到緊急伺服器了，現在只要按下按鈕……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SPEAKER_DEBT_NULL_NULL","text":{"KOREA":"어라.","JPN":"あれ。","ENG":"Huh?","TWN":"咦。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SPEAKER_DEBT_NULL_NULL","text":{"KOREA":"잘못…","JPN":"違うやつを……","ENG":"I think...","TWN":"錯了……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SPEAKER_DEBT_NULL_NULL","text":{"KOREA":" 누른 것 같은데.","JPN":" 押しちゃったみたいだけど。","ENG":" I pressed the wrong one.","TWN":"好像按錯了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>긴급 프로토콜 시스템 가동. 현 시간부로 선내 모든 데이터의 말소 작업을 시작합니다.</color>","JPN":"<color=#ffd34c>緊急プロトコルシステム稼働。現時間をもって船内の全データの抹消作業を開始します。</color>","ENG":"<color=#ffd34c>Emergency protocol system activated. Beginning the deletion process of all data on the ship.</color>","TWN":"<color=#ffd34c>啟動緊急協定系統。開始刪除艦內所有資料。</color>"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L1_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>반복합니다. 현 시간부로 말소 작업을 개시. 선내 모든 인원은 즉시 대피하시기 바랍니다.</color>","JPN":"<color=#ffd34c>繰り返します。現時間をもって抹消作業を開始。船内の総員は直ちに避難してください。</color>","ENG":"<color=#ffd34c>Attention. The deletion process of all data on the ship will begin. All personnel on board are requested to evacuate immediately.</color>","TWN":"<color=#ffd34c>再次通知，從現在開始進行刪除作業。船內所有人員請立即撤離。</color>"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L3_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"탈리, 너…….","JPN":"タリー、あなた……","ENG":"Tallie...?","TWN":"塔莉，你……"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L4_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"억울해요. 이번엔 제 탓이 아니라구요!","JPN":"無実です。これは私のせいじゃないですわ！","ENG":"No! It wasn't me this time!","TWN":"冤枉啊。這次真的不是我的錯！"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L5_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"설마 대포가 영 좋지 않은 곳에 맞은 건가?!","JPN":"まさか、大砲が変なところに当たったの！？","ENG":"Or maybe my cannon hit something it shouldn't have?!","TWN":"難道是大炮打到了不該打的地方？"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L7_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"쯧. 설마 했는데 아까 그 녀석 짓인 모양이네.","JPN":"ちっ。まさかと思ったが、さっきのあいつの仕業のようだ。","ENG":"Tch. I wasn't sure, but I guess it was that girl's doing.","TWN":"嘖。真沒想到，是剛才那傢伙幹的好事吧。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"어이 터커! 이 정도 규모의 함선이라면 구명정 정도는 있겠지?","JPN":"おい、ターカー！　この規模の艦船なら、救命艇くらいはあるだろ？","ENG":"Hey, Tucker! A ship of this size should have a lifeboat, right?","TWN":"喂，塔克！這麼大的艦船，應該有救生艇吧？"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L10_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"죽이 되든 밥이 되든 일단 살고 보자고. 너도 여기서 수장되기는 싫을 거 아니야?","JPN":"とにかく命が大事だ。お前もここで海の藻屑となりたくはないよな？","ENG":"Let's put our differences aside for now and focus on surviving. You don't want to be buried out here, do you?","TWN":"不管誰死誰活，先逃命再說。你也不想在這裡被淹死吧！"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_NULL","text":{"KOREA":"웃기지 마! 멋대로 날뛰고는 이제 와서 화해하자고?","JPN":"ふざけんな！　勝手に暴れておいて、今更和解しようってのか？","ENG":"Don't kid yourself! You want to make amends after causing all that ruckus?!","TWN":"開什麼玩笑！鬧事的人是你，現在要和解的也是你？"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_NULL","text":{"KOREA":"편의점 아가씨도 그쪽이 인질로 잡았잖아!","JPN":"コンビニの嬢ちゃんもそっちが人質に取ったんだろう！","ENG":"You even have that convenience store girl as your hostage!","TWN":"你不是還把便利商店的小妹妹當做人質嗎！"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"아마추어 같이 왜 이래? 원래 해적은 목적이 아닌 상황에 맞춰 움직이는 거라고.","JPN":"なに素人じみたこと言ってんだ？　元来海賊は目的じゃなく状況に合わせて動くもんだ。","ENG":"Quit acting like an amateur! Pirates are supposed to act upon the situation, not their goals!","TWN":"你怎麼像個業餘的？真正的海盜是根據情況而不是目標來行動的。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"함선의 주요 기능을 건드릴 수 있는 아가씨야. 괜히 휘말렸다간 좋은 꼴 못 본다?","JPN":"艦船の主要機能をいじれる嬢ちゃんだ。巻き込まれるとめんどくさくなるだろ？","ENG":"She can access to the ship's main functions. Nothing good will come out of getting involved with her.","TWN":"她可是能操控艦船主系統的人。和她待一起，可沒什麼好下場喔？"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"설마 아무런 대책 없이 자폭 버튼을 건드렸을까, 캬하핫-.","JPN":"まさか、なんの考えもなしに自爆ボタンを押してないだろ。キャハハッー","ENG":"Who presses the self-destruct button without a plan? Kya hah hah!","TWN":"誰會不留後手就按下自爆按鈕啊，哈哈哈——"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SPEAKER_DEBT_NULL_NULL","text":{"KOREA":"으읍! 으으읍!!","JPN":"ううっ！　うううっ！！","ENG":"Mmf! Mmph!!","TWN":"唔！唔唔唔！！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L20_1","type":"dialog","speaker":"SPEAKER_DEBT_NULL_NULL","text":{"KOREA":"으으으으읍!!!","JPN":"うううううっ！！！","ENG":"MMMMPH!!!","TWN":"唔唔唔唔唔！！！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L22_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"정해. 싸우다 물고기 밥이 될지. 아니면 그 머리카락 같은 자존심 좀 굽힐지.","JPN":"決めろ。戦って魚のエサになるか、それともその小さなプライドを捨てるか。","ENG":"Choose. Either fight us and we all become fish food. Or you yield your stubborn pride.","TWN":"決定吧。是要打一場後成為魚餌，還是稍微放下你那點自尊心。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"선장은 배는 버려도 선원은 버리지 않는 법이라고, 짝퉁 씨.","JPN":"船長たるもの船は捨てても船員は捨てないもんなんだよ、ニセ物。","ENG":"The captain may abandon the ship, but they don't abandon the crew, Mr. Knockoff!","TWN":"船長就算是丟下船，也不會丟下船員的，冒牌貨先生。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_NULL","text":{"KOREA":"그러니까 짝퉁이 아니라고!","JPN":"だから、ニセ物じゃない！","ENG":"Like I said, I'm not copying you!","TWN":"就說我不是冒牌貨！"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_NULL","text":{"KOREA":"칫. 선원들 얼굴을 봐서 지금은 넘어가는 줄 알아.","JPN":"ちっ。船員たちもいるから今は勘弁してやる。","ENG":"Tch. Just know that I'm only doing this for my crew, okay?","TWN":"哼，看在船員們的面子上，這次就算了。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_NULL","text":{"KOREA":"준비해! 여기서 빠져나간다!","JPN":"準備しろ！　ここから抜け出す！","ENG":"All hands! Prepare to abandon ship!","TWN":"大家！準備棄船！"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SPEAKER_DEBT_NULL_NULL","text":{"KOREA":"으으으읍!!","JPN":"ううううっ！！","ENG":"MMMMMPH!!","TWN":"唔唔唔！！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L34_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"다들 탔네. 빨리 출발하자고.","JPN":"全員乗ったね。早く出発しよう。","ENG":"We're all here. Now, let's get out of here.","TWN":"大家都上來了，快點出發吧。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_SEAWAVE"},{"id":"L36_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"있죠, 선장님.","JPN":"ねえ、船長。","ENG":"Hey, Captain?","TWN":"船長，我有話說。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"좀 봐줘라. 네가 그런 표정일 때는 일이 정상적으로 흘러가는 경우가 없었다고.","JPN":"勘弁してくれよ。お前がそんな顔をする時は、すんなりと終わったことがなかったんだ。","ENG":"Please don't. Nothing ever goes right when you make that face.","TWN":"算我求你……每次你露出那種表情的時候，都沒好事發生。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"너무해요! 전 그냥 터지는 배라면 쏴도 문제없을까 하고…!","JPN":"ひどいですわ！　私はただ、爆発する船なら撃ってもいいのかなーって……！","ENG":"Rude! I was just wondering if it'll be a problem if I shoot the already-exploding ship...!","TWN":"好過分！我只是想說，反正是快爆炸的船，我開炮炸它應該也沒關係吧……！"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"안 쏘고 물어보는 것만으로도 탈리 기준으로는 합격점이네.","JPN":"撃たずにまず聞いてみるだけでもタリーにしては合格点だな。","ENG":"By Tallie's standards, she's already done enough by asking before pulling the trigger.","TWN":"動手前先詢問的話，以塔莉的標準來看已經算合格了。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_HATE"},"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L41_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"어떻게 생각해, 선장?","JPN":"どう思う？　船長。","ENG":"What do you think, Captain?","TWN":"你怎麼看，船長？"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_HATE"},"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L42_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"캬하핫- 마음대로 해. 어차피 가는 거 우리 손으로 보내주자고.","JPN":"キャハハッー勝手にしろよ。どうせならあたしたちの手で逝かせてやろうじゃないか。","ENG":"Kya hah hah! Do what you want. If it's already going down, let's send it off with our own hands.","TWN":"哼哼哼，隨你便。反正是要沉的，親手送一程也是一樣的。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L43_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"역시 선장님! 최고의 해적! 사랑해요!","JPN":"さすが船長！　最高の海賊！　大好き！","ENG":"Captain! You're the best! I love you!","TWN":"耶！你是最棒的海盜，船長！我愛你！"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_PRIDE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L48_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"그럼……","JPN":"じゃあ……","ENG":"Then...","TWN":"那麼……"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS2"},"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L1_1","type":"dialog","speaker":"SPEAKER_DEBT_NULL_NULL","text":{"KOREA":"으읍… 으으…읍…….","JPN":"ううっ……うう……うっ……","ENG":"Mmmf... Mm... Mmph...","TWN":"唔、唔唔……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_SIREN"},{"id":"L2_1","type":"dialog","speaker":"SPEAKER_DEBT_NULL_NULL","text":{"KOREA":"으읍……!","JPN":"ううっ……！","ENG":"MMMMPH...!","TWN":"唔……！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L5_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"해적들의 로망… 폭발 엔딩이다!","JPN":"海賊のロマン……爆発エンディングだ！","ENG":"A pirate's dream...! Ending it with a kaboom!","TWN":"海盜們的浪漫……！轟轟烈烈的大場面！"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_MISSILE_RELOAD"},{"id":"L14_1","type":"dialog","speaker":"YUMI_POLICE_SUMMER_NULL","text":{"KOREA":"그래서.","JPN":"で。","ENG":"So...","TWN":"好的，"},"stage":{"bg":"FRONTBAY_WALL","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_SEAWAVE"},{"id":"L15_1","type":"dialog","speaker":"YUMI_POLICE_SUMMER_NULL","text":{"KOREA":"진술은 그걸로 끝인가요?","JPN":"陳述はそれで終わりですか？","ENG":"Is that all you have to say?","TWN":"這就是事情發生的經過嗎？"},"stage":{"bg":"FRONTBAY_WALL","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SPEAKER_DEBT_NULL_NULL","text":{"KOREA":"네, 끝났슴돠…….","JPN":"はい、終わりっす……","ENG":"Yup. I've said everything...","TWN":"是，這就是全部了……"},"stage":{"bg":"FRONTBAY_WALL","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_SUMMER","text":{"KOREA":"요즘 시대에 함선 테러라니. 아무리 그래도 좀 무리수가 아닌가 싶네요~.","JPN":"今の時代に艦船テロって。いくらなんでも無理すぎる気がするんですけど～","ENG":"A ship terrorist in this age. A bit unreasonable, don't you think?","TWN":"哈哈，這個年代還搞艦船恐怖攻擊，怎麼想都覺得有點過分吧～"},"stage":{"bg":"FRONTBAY_WALL","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_SUMMER","face":"UNIT_LAUGH"}}}},{"id":"L21_1","type":"dialog","speaker":"SPEAKER_DEBT_NULL_NULL","text":{"KOREA":"믿으실지 모르겠지만 모함이랄까. 결백한 건 아닌데 무죄에 가깝달까.","JPN":"信じられるかわからないですけど、罠っていうか。潔白ではないけど、無罪に近いというか。","ENG":"I'm not sure if you believe me, but it was a set-up. I'm not innocent, just closer to not guilty.","TWN":"你可能不信，但我是被誣陷的。雖然不是完全無辜，但也差不多……"},"stage":{"bg":"FRONTBAY_WALL","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_SUMMER","face":"UNIT_LAUGH"}}}},{"id":"L22_1","type":"dialog","speaker":"SPEAKER_DEBT_NULL_NULL","text":{"KOREA":"눈떠보니 아무도 없어서 저한테 덤터기 씌워진 거랄까…….","JPN":"目覚めてみたら誰もいなくて、私になすりつけられたというか……","ENG":"When I opened my eyes, everyone was gone and I got framed...","TWN":"睜開眼的時候，周圍一個人都沒有……"},"stage":{"bg":"FRONTBAY_WALL","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_SUMMER","face":"UNIT_LAUGH"}}}},{"id":"L24_1","type":"dialog","speaker":"YUMI_POLICE_SUMMER_NULL","text":{"KOREA":"네네. 나머진 송치된 뒤에 말씀하시죠.","JPN":"はい、はい。後は送致してから話してください。","ENG":"Yeah, yeah. You can tell us the rest after we transfer you over.","TWN":"是是是，其他的等移交結束後再說吧。"},"stage":{"bg":"FRONTBAY_WALL","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_SUMMER_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"YUMI_POLICE_SUMMER_NULL","text":{"KOREA":"정말이지. 모처럼 휴가였는데 이런 사건이라니.","JPN":"まったく。せっかく休みだったのにこんな事件が起きるなんて。","ENG":"I can't believe this just had to happen on my day off.","TWN":"真是的。好不容易休假，竟然遇到這種事。"},"stage":{"bg":"FRONTBAY_WALL","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_SUMMER","text":{"KOREA":"그래도 기업에 연루된 만큼 프론트베이에서 징역노동자가 될 일은 없겠네요.","JPN":"でも企業が関わってる以上、フロントベイで懲役労働者になることはなさそうですね。","ENG":"But at least you won't become a sentenced laborer in Front Bay since a corporation is involved.","TWN":"不過，既然牽涉到企業，就不會成為被送到前灣做苦工吧。"},"stage":{"bg":"FRONTBAY_WALL","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_SUMMER","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_SUMMER","text":{"KOREA":"불행 중 희소식~ 뭐 그런 거 아닐까요? 하하.","JPN":"不幸中の幸い～まあ、そんなところじゃないですか？　はは。","ENG":"It could've been worse, you know? Haha.","TWN":"這就是所謂的不幸中的大幸吧？哈哈。"},"stage":{"bg":"FRONTBAY_WALL","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_SUMMER","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"YUMI_POLICE_SUMMER_NULL","text":{"KOREA":"강소영 경위!!","JPN":"マエカワ警部補！！","ENG":"Lieutenant Kang!!","TWN":"姜素英警官！！"},"stage":{"bg":"FRONTBAY_WALL","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_SUMMER","face":"UNIT_LAUGH"},"R":{"char_id":"YUMI_POLICE_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L30_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_SUMMER","text":{"KOREA":"네네. 죄송합니다.","JPN":"はいはい。すみませんでした。","ENG":"Yeah, yeah. Sorry about that.","TWN":"好好。對不起。"},"stage":{"bg":"FRONTBAY_WALL","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_SUMMER","face":"UNIT_DESPAIR"},"R":{"char_id":"YUMI_POLICE_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L33_1","type":"dialog","speaker":"YUMI_POLICE_SUMMER_NULL","text":{"KOREA":"하아… 마지막으로 하실 말씀 있나요?","JPN":"はあ……最後に言いたいことはありますか？","ENG":"*Sigh* Any final words?","TWN":"哀……最後有什麼要說的嗎？"},"stage":{"bg":"FRONTBAY_WALL","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SPEAKER_DEBT_NULL_NULL","text":{"KOREA":"그, 모처럼 휴가신데 물의를 일으켜 죄송합니다.","JPN":"その、せっかくの休暇中に騒ぎを起こしてすみませんでした。","ENG":"Uh... I'm sorry for causing trouble on your day off.","TWN":"那個，很抱歉在難得的假期裡給你添麻煩。"},"stage":{"bg":"FRONTBAY_WALL","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SPEAKER_DEBT_NULL_NULL","text":{"KOREA":"한 번만 봐주세요오오오오!!!","JPN":"一度だけでいいので見逃してくださいいいいい！！！","ENG":"Could you just let me off with a warning? Pleaaaaaase!","TWN":"拜託放我一馬吧！！！"},"stage":{"bg":"SKY","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};